// Day Counter — weekday-based 90-day counter starting March 2, 2026
function getWeekdayDates() {
  const dates = [];
  const d = new Date(Date.UTC(2026, 2, 2));
  while (dates.length < 90) {
    if (d.getUTCDay() !== 0 && d.getUTCDay() !== 6) dates.push(d.toISOString().split('T')[0]);
    d = new Date(d.getTime() + 86400000);
  }
  return dates;
}
const weekdays = getWeekdayDates();
const now = new Date();
const todayStr = now.toLocaleDateString('en-CA', { timeZone: 'Africa/Lagos' });
let dayNum = null;
for (let i = 0; i < weekdays.length; i++) {
  if (weekdays[i] === todayStr) { dayNum = i + 1; break; }
}
const watDay = new Date(todayStr + 'T12:00:00Z').getUTCDay();
const isWeekend = watDay === 0 || watDay === 6;
const weekNum = dayNum ? Math.ceil(dayNum / 5) : null;
return [{ json: { day_number: dayNum, week_num: weekNum, is_weekend: isWeekend, date: todayStr } }];

// Task Window Checker — updated for 90-Day War Plan schedule
const TASK_WINDOWS = [
  { task: 'prayer_session_1', start: '03:00', end: '04:15' },
  { task: 'coding_block_1',   start: '04:30', end: '06:20' },
  { task: 'nt_reading',       start: '06:30', end: '07:30' },
  { task: 'book_reading',     start: '08:00', end: '09:00' },
  { task: 'career_block_a',   start: '09:00', end: '11:50' },
  { task: 'career_block_b',   start: '12:00', end: '13:50' },
  { task: 'coding_block_2',   start: '14:00', end: '16:50' },
  { task: 'prayer_session_2', start: '17:00', end: '18:20' },
  { task: 'career_block_c',   start: '19:30', end: '21:20' },
  { task: 'coding_block_3',   start: '21:30', end: '23:00' }
];

const now = new Date();
const currentTime = now.getHours().toString().padStart(2,'0') + ':' + now.getMinutes().toString().padStart(2,'0');

const overdueWindows = TASK_WINDOWS.filter(w => currentTime > w.end);
const activeWindows = TASK_WINDOWS.filter(w => currentTime >= w.start && currentTime <= w.end);

return [{ json: { ...$input.first().json, overdue_tasks: overdueWindows.map(w => w.task), active_tasks: activeWindows.map(w => w.task), current_time: currentTime } }];

// Compare overdue tasks against daily_log completions and existing escalations
const dayData = $('Get Daily Log').first().json;
const prevEscalations = $('Get Escalations').first().json || [];
const overdueItems = $('Task Window Checker').first().json.overdue_tasks || [];
const config = $('Read Config').first().json;
const dayNum = $('Day Counter').first().json.day_number;

const TASK_FIELD_MAP = {
  'prayer_session_1': 'prayer_s1',
  'prayer_session_2': 'prayer_s2',
  'nt_reading': 'nt_chapters_read',
  'book_reading': 'book_pages',
  'coding_block_1': 'code_hrs',
  'coding_block_2': 'code_hrs',
  'coding_block_3': 'code_hrs',
  'career_block_a': 'career_done',
  'career_block_b': 'career_done',
  'career_block_c': 'career_done'
};

const escalations = [];
for (const task of overdueItems) {
  const field = TASK_FIELD_MAP[task];
  if (!field) continue;
  const val = Array.isArray(dayData) && dayData[0] ? dayData[0][field] : null;
  const isDone = val && (val === true || (Array.isArray(val) && val.length > 0) || (typeof val === 'number' && val > 0));
  if (isDone) continue;
  // Check if already escalated at this level
  const existing = (Array.isArray(prevEscalations) ? prevEscalations : []).filter(e => e.task === task);
  const maxLevel = existing.length > 0 ? Math.max(...existing.map(e => e.level || 0)) : 0;
  if (maxLevel < 3) {
    escalations.push({ task, level: maxLevel + 1, day_num: dayNum });
  }
}
// Count total missed today
const totalMissed = escalations.length;
if (totalMissed >= 3) {
  escalations.forEach(e => e.level = Math.max(e.level, 4));
}

return [{ json: { escalations, has_escalation: escalations.length > 0, total_missed: totalMissed } }];

